 1	import * as React from 'react';
 2	import {
 3	  IBM_SCALE_NAMESPACE,
 4	  IBM_SCALE_OPERATOR_NAME,
 5	} from '@odf/core/constants';
 6	import { ClusterKind } from '@odf/core/types/scale';
 7	import { useCustomTranslation, useFetchCsv } from '@odf/shared';
 8	import HealthItem from '@odf/shared/dashboards/status-card/HealthItem';
 9	import { ClusterModel as SANClusterModel } from '@odf/shared/models/scale';
10	import { getOperatorHealthState, referenceForModel } from '@odf/shared/utils';
11	import {
12	  HealthState,
13	  useK8sWatchResource,
14	} from '@openshift-console/dynamic-plugin-sdk';
15	import {
16	  Card,
17	  CardBody,
18	  CardHeader,
19	  CardTitle,
20	  Gallery,
21	  GalleryItem,
22	} from '@patternfly/react-core';
23	
24	const getLocalClusterHealth = (
25	  cluster: ClusterKind,
26	  loading: boolean,
27	  loadError: any
28	) => {
29	  if (loading) {
30	    return HealthState.LOADING;
31	  }
32	  if (loadError) {
33	    return HealthState.ERROR;
34	  }
35	  if (!cluster) {
36	    return HealthState.NOT_AVAILABLE;
37	  }
38	  const clusterConnectionStatus = cluster?.status?.conditions?.find(
39	    (condition) => condition.type === 'Success'
40	  ).status;
41	  return clusterConnectionStatus === 'True'
42	    ? HealthState.OK
43	    : HealthState.ERROR;
44	};
45	
46	const StatusCard: React.FC<{}> = () => {
47	  const { t } = useCustomTranslation();
48	  const [ibmCSV, ibmCsvLoaded, ibmCsvLoadError] = useFetchCsv({
49	    specName: IBM_SCALE_OPERATOR_NAME,
50	    namespace: IBM_SCALE_NAMESPACE,
51	  });
52	
53	  const [localCluster, localClusterLoaded, localClusterLoadError] =
54	    useK8sWatchResource<ClusterKind[]>({
55	      kind: referenceForModel(SANClusterModel),
56	      isList: true,
57	      namespace: IBM_SCALE_NAMESPACE,
58	    });
59	
60	  const flashOperator = getOperatorHealthState(
61	    ibmCSV?.status?.phase,
62	    !ibmCsvLoaded,
63	    ibmCsvLoadError
64	  );
65	
66	  const localClusterHealth = getLocalClusterHealth(
67	    localCluster?.[0],
68	    !localClusterLoaded,
69	    localClusterLoadError
70	  );
71	
72	  return (
73	    <Card>
74	      <CardHeader>
75	        <CardTitle>{t('Status')}</CardTitle>
76	      </CardHeader>
77	      <CardBody>
78	        <Gallery hasGutter>
79	          <GalleryItem>
80	            <HealthItem title={t('Operator')} state={flashOperator.state} />
81	          </GalleryItem>
82	          <GalleryItem>
83	            <HealthItem title={t('Connection')} state={localClusterHealth} />
84	          </GalleryItem>
85	        </Gallery>
86	      </CardBody>
87	    </Card>
88	  );
89	};
90	
91	export default StatusCard;

